// Processar dados da mensagem da Evolution API
const messageData = $input.first().json;

// Extrair informações da mensagem
const message = messageData.data;
const instanceName = messageData.instance || 'default';

// Processar cada mensagem no array
const processedMessages = [];

if (message && message.messages) {
  for (const msg of message.messages) {
    const processedMsg = {
      user_id: null, // Será preenchido baseado na instância
      instance_name: instanceName,
      message_id: msg.key?.id,
      from_jid: msg.key?.remoteJid,
      to_jid: msg.key?.remoteJid,
      message_text: msg.message?.conversation || 
                   msg.message?.extendedTextMessage?.text ||
                   msg.message?.imageMessage?.caption ||
                   'Media message',
      message_timestamp: new Date(msg.messageTimestamp * 1000).toISOString(),
      from_me: msg.key?.fromMe || false,
      message_type: 'text'
    };

    // Determinar tipo de mensagem
    if (msg.message?.imageMessage) {
      processedMsg.message_type = 'image';
      processedMsg.media_url = msg.message.imageMessage.url;
      processedMsg.media_caption = msg.message.imageMessage.caption;
    } else if (msg.message?.videoMessage) {
      processedMsg.message_type = 'video';
      processedMsg.media_url = msg.message.videoMessage.url;
      processedMsg.media_caption = msg.message.videoMessage.caption;
    } else if (msg.message?.documentMessage) {
      processedMsg.message_type = 'document';
      processedMsg.media_url = msg.message.documentMessage.url;
      processedMsg.media_caption = msg.message.documentMessage.fileName;
    }

    processedMessages.push(processedMsg);
  }
}

// Retornar mensagens processadas
return processedMessages.map(msg => ({ json: msg }));

